/* D-LOGIC ATLAS - i18n (PL/EN/DE). Slowniki + graceful fallback do PL.
   Jezyk z localStorage dlogic-lang (sync z SiteNav); przelaczenie => reload,
   wiec LANG staly na czas strony. Brak tlumaczenia => PL (nigdy nie psuje).
   t(pl) prosta fraza; td(key,plFb) pole danych; T tagged-template NLG po szkielecie. */
export function getLang(){
  try { const l = localStorage.getItem('dlogic-lang'); if (l==='en'||l==='de'||l==='pl') return l; } catch(e){}
  const h = (typeof document!=='undefined' && document.documentElement.lang) || 'pl';
  return (h==='en'||h==='de') ? h : 'pl';
}
